//! AUTO-GENERATED by the spec-word-compliance workflow.
//!
//! Area: "Math under tracked changes: m:ins/m:del control characters + math in
//! inserted/deleted runs".
//!
//! Each `#[test]` encodes a Word-consumption / serialization constraint mined
//! from ECMA-376 §17.13.5.{13,14,16,18}, §22.1.2.23, the OMML schema
//! (CT_MathCtrlDel / CT_MathCtrlIns / EG_RPrMath), and MS-OI29500 §2.1.329 /
//! §2.1.332. A FAILING assertion is NOT a flaky test to be silenced: it encodes
//! a real divergence between stemma and Microsoft Word (the consumption oracle).
//! Fix at the source per CLAUDE.md — never weaken the assertion to make it pass.
//!
//! Methodology guardrails (consumption vs. save):
//! - `xmlContains` / `xmlOmits` / regex-as-contains on `reserialize()` are used
//!   only for markup stemma ACTIVELY preserves/restructures verbatim (opaque
//!   math passthrough) and for structural validity — never for "Word normalizes
//!   value V on render".
//! - Word CONSUMPTION semantics (what accept/reject means) are asserted on the
//!   read side via `read_accepted()` / `read_rejected()` -> `to_text()`.

use std::io::{Read, Write};

use stemma::ExportOptions;
use stemma::api::{Document, validate};
use zip::ZipArchive;
use zip::write::FileOptions;

// ─── Prelude: minimal-.docx plumbing ────────────────────────────────────────

/// Build a valid minimal `.docx` whose `word/document.xml` body is `body_xml`
/// (wrapped in `<w:document ...><w:body>…</w:body></w:document>`). The `w:` and
/// `m:` namespaces are declared on the root so any OMML / tracked-change markup
/// in `body_xml` resolves. `extra_parts` are written verbatim under their given
/// part path (e.g. `("word/styles.xml", "<w:styles…/>")`); each non-`.rels`,
/// non-`.xml`-defaulted part also gets a content-type override.
fn make_docx(body_xml: &str, extra_parts: &[(&str, &str)]) -> Vec<u8> {
    let document_xml = format!(
        r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<w:document xmlns:w="http://schemas.openxmlformats.org/wordprocessingml/2006/main" xmlns:m="http://schemas.openxmlformats.org/officeDocument/2006/math"><w:body>{body_xml}</w:body></w:document>"#
    );

    // Content-type overrides for any extra parts.
    let mut overrides = String::from(
        r#"<Override PartName="/word/document.xml" ContentType="application/vnd.openxmlformats-officedocument.wordprocessingml.document.main+xml"/>"#,
    );
    for (part, _) in extra_parts {
        let ct = match *part {
            "word/styles.xml" => {
                Some("application/vnd.openxmlformats-officedocument.wordprocessingml.styles+xml")
            }
            "word/numbering.xml" => {
                Some("application/vnd.openxmlformats-officedocument.wordprocessingml.numbering+xml")
            }
            _ => None,
        };
        if let Some(ct) = ct {
            overrides.push_str(&format!(
                r#"<Override PartName="/{part}" ContentType="{ct}"/>"#
            ));
        }
    }

    let content_types = format!(
        r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?><Types xmlns="http://schemas.openxmlformats.org/package/2006/content-types"><Default Extension="rels" ContentType="application/vnd.openxmlformats-package.relationships+xml"/><Default Extension="xml" ContentType="application/xml"/>{overrides}</Types>"#
    );
    let rels = r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships"><Relationship Id="rId1" Type="http://schemas.openxmlformats.org/officeDocument/2006/relationships/officeDocument" Target="word/document.xml"/></Relationships>"#;
    let doc_rels = r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships"/>"#;

    let mut buf = Vec::new();
    {
        let mut zip = zip::ZipWriter::new(std::io::Cursor::new(&mut buf));
        let opts: FileOptions = FileOptions::default();
        zip.start_file("[Content_Types].xml", opts).unwrap();
        zip.write_all(content_types.as_bytes()).unwrap();
        zip.start_file("_rels/.rels", opts).unwrap();
        zip.write_all(rels.as_bytes()).unwrap();
        zip.start_file("word/_rels/document.xml.rels", opts)
            .unwrap();
        zip.write_all(doc_rels.as_bytes()).unwrap();
        zip.start_file("word/document.xml", opts).unwrap();
        zip.write_all(document_xml.as_bytes()).unwrap();
        for (part, contents) in extra_parts {
            zip.start_file(*part, opts).unwrap();
            zip.write_all(contents.as_bytes()).unwrap();
        }
        zip.finish().unwrap();
    }
    buf
}

/// Unzip `docx` and return `word/document.xml` as a String.
fn document_xml_of(docx: &[u8]) -> String {
    let mut zip = ZipArchive::new(std::io::Cursor::new(docx)).expect("open docx zip");
    let mut file = zip.by_name("word/document.xml").expect("word/document.xml");
    let mut s = String::new();
    file.read_to_string(&mut s).expect("read document.xml");
    s
}

/// Parse -> serialize -> return the re-serialized `word/document.xml`.
fn reserialize(bytes: &[u8]) -> String {
    let doc = Document::parse(bytes).expect("parse");
    let out = doc.serialize(&ExportOptions::default()).expect("serialize");
    document_xml_of(&out)
}

/// Accept-all visible text (trimmed).
fn accept_text(bytes: &[u8]) -> String {
    Document::parse(bytes)
        .expect("parse")
        .read_accepted()
        .expect("read_accepted")
        .to_text()
}

/// Reject-all visible text (trimmed).
fn reject_text(bytes: &[u8]) -> String {
    Document::parse(bytes)
        .expect("parse")
        .read_rejected()
        .expect("read_rejected")
        .to_text()
}

/// Assert the document opens clean (validator reports no issues).
fn assert_opens_clean(bytes: &[u8], ctx: &str) {
    let report = validate(bytes);
    assert!(
        report.ok && report.issues.is_empty(),
        "{ctx} — expected opens-clean (no validator issues), got ok={} issues={:?}",
        report.ok,
        report.issues
    );
}

