#[test]
fn math_ctrl_del_inside_ctrlpr_not_consumed_as_run_deletion() {
    let body = r#"<w:p><w:r><w:t xml:space="preserve">Let </w:t></w:r><m:oMath xmlns:m="http://schemas.openxmlformats.org/officeDocument/2006/math"><m:f><m:fPr><m:ctrlPr><w:del w:id="5" w:author="Joe Smith" w:date="2006-03-31T12:50:00Z"><w:rPr/></w:del></m:ctrlPr></m:fPr><m:num><m:r><m:t>a</m:t></m:r></m:num><m:den><m:r><m:t>b</m:t></m:r></m:den></m:f></m:oMath><w:r><w:t xml:space="preserve"> be.</w:t></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);

    assert_eq!(
        accept_text(&b).trim(),
        "Let \u{FFFC} be.",
        "ECMA-376 §17.13.5.13 / MS-OI29500 §2.1.329 / §22.1.2.23 — the inner w:del is a math-control-character revision (CT_MathCtrlDel) in m:ctrlPr, not a run-content deletion; accept-all must leave the oMath object in place (exactly one U+FFFC)."
    );
    assert_eq!(
        reject_text(&b).trim(),
        "Let \u{FFFC} be.",
        "ECMA-376 §17.13.5.13 / MS-OI29500 §2.1.329 — rejecting a control-character deletion restores the control char but the oMath object never disappears; reject-all still shows exactly one U+FFFC."
    );
    assert_opens_clean(
        &b,
        "MS-OI29500 §2.1.329 / ECMA-376 §17.13.5.13 — Word accepts CT_MathCtrlDel (w:del in m:ctrlPr) as valid",
    );
}

#[test]
fn math_ctrl_del_roundtrips_verbatim_inside_ctrlpr() {
    let body = r#"<w:p><w:r><w:t xml:space="preserve">Let </w:t></w:r><m:oMath xmlns:m="http://schemas.openxmlformats.org/officeDocument/2006/math"><m:f><m:fPr><m:ctrlPr><w:del w:id="5" w:author="Joe Smith" w:date="2006-03-31T12:50:00Z"><w:rPr/></w:del></m:ctrlPr></m:fPr><m:num><m:r><m:t>a</m:t></m:r></m:num><m:den><m:r><m:t>b</m:t></m:r></m:den></m:f></m:oMath><w:r><w:t xml:space="preserve"> be.</w:t></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);
    let xml = reserialize(&b);

    assert!(
        xml.contains("<m:ctrlPr>"),
        "ECMA-376 §22.1.2.23 — the m:ctrlPr wrapper around the deleted control character must survive serialization (opaque math preserved verbatim); got:\n{xml}"
    );
    // xmlRegex `<m:ctrlPr>\s*<w:del[^>]*>` translated to a contains check:
    // stemma preserves opaque math byte-verbatim, so the source's adjacent
    // `<m:ctrlPr><w:del` (no whitespace) must re-emit unchanged. The w:del must
    // stay a direct child of m:ctrlPr, not be hoisted to run level.
    assert!(
        xml.contains("<m:ctrlPr><w:del"),
        "ECMA-376 §17.13.5.13 — the math-control-character w:del must remain a direct child of m:ctrlPr, not be hoisted out of the math object; got:\n{xml}"
    );
    assert!(
        !xml.contains("delText"),
        "ECMA-376 §17.13.5.13 (CT_MathCtrlDel) / MS-OI29500 §2.1.329 — a deleted math control character carries an rPr, never a w:delText; the serializer must not synthesize one; got:\n{xml}"
    );
}

#[test]
fn inserted_inline_equation_wrapped_in_w_ins_kept_on_accept_dropped_on_reject() {
    let body = r#"<w:p><w:r><w:t xml:space="preserve">See </w:t></w:r><w:ins w:id="7" w:author="A" w:date="2006-03-31T12:50:00Z"><w:r><m:oMath xmlns:m="http://schemas.openxmlformats.org/officeDocument/2006/math"><m:r><m:t>x</m:t></m:r></m:oMath></w:r></w:ins><w:r><w:t xml:space="preserve"> now.</w:t></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);

    assert_eq!(
        accept_text(&b).trim(),
        "See \u{FFFC} now.",
        "ECMA-376 §17.13.5.18 — accepting the run-content insertion materializes the inserted inline math (exactly one U+FFFC opaque anchor)."
    );
    assert_eq!(
        reject_text(&b).trim(),
        "See  now.",
        "ECMA-376 §17.13.5.18 — rejecting the insertion removes the entire inserted inline equation; no U+FFFC remains between the surrounding text."
    );
    assert_opens_clean(
        &b,
        "ECMA-376 §22.1.2.77 / §17.13.5.18 — an oMath inside a w:ins run is valid markup Word opens without repair",
    );
}

#[test]
fn deleted_inline_equation_wrapped_in_w_del_dropped_on_accept_kept_on_reject() {
    let body = r#"<w:p><w:r><w:t xml:space="preserve">See </w:t></w:r><w:del w:id="8" w:author="A" w:date="2006-03-31T12:50:00Z"><w:r><m:oMath xmlns:m="http://schemas.openxmlformats.org/officeDocument/2006/math"><m:r><m:t>x</m:t></m:r></m:oMath></w:r></w:del><w:r><w:t xml:space="preserve"> now.</w:t></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);

    assert_eq!(
        accept_text(&b).trim(),
        "See  now.",
        "ECMA-376 §17.13.5.14 — accepting a run-content deletion removes all deleted content, including the entire inline equation; no U+FFFC remains."
    );
    assert_eq!(
        reject_text(&b).trim(),
        "See \u{FFFC} now.",
        "ECMA-376 §17.13.5.14 — rejecting the deletion restores the deleted inline equation (exactly one U+FFFC opaque anchor)."
    );
    assert_opens_clean(
        &b,
        "ECMA-376 §22.1.2.77 / §17.13.5.14 — an oMath inside a w:del run is valid markup Word opens without repair",
    );
}

#[test]
fn math_ctrl_ins_with_rpr_child_no_rprchange_opens_clean_and_roundtrips() {
    let body = r#"<w:p><w:r><w:t xml:space="preserve">Eq </w:t></w:r><m:oMath xmlns:m="http://schemas.openxmlformats.org/officeDocument/2006/math"><m:f><m:fPr><m:ctrlPr><w:ins w:id="9" w:author="A" w:date="2006-03-31T12:50:00Z"><w:rPr/></w:ins></m:ctrlPr></m:fPr><m:num><m:r><m:t>a</m:t></m:r></m:num><m:den><m:r><m:t>b</m:t></m:r></m:den></m:f></m:oMath></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);

    assert_opens_clean(
        &b,
        "MS-OI29500 §2.1.332 — Word accepts a math-control ins carrying a w:rPr child (even empty); stemma must report it opens clean",
    );
    let xml = reserialize(&b);
    // xmlRegex `<m:ctrlPr>\s*<w:ins[^>]*>` -> verbatim adjacency contains check.
    assert!(
        xml.contains("<m:ctrlPr><w:ins"),
        "ECMA-376 §17.13.5.16 — the inserted math-control-character w:ins must remain a direct child of m:ctrlPr through serialization (oMath verbatim); got:\n{xml}"
    );
    assert!(
        !xml.contains("rPrChange"),
        "MS-OI29500 §2.1.332 — the valid child is rPr (Run Properties), not rPr (Previous Run Properties); the serializer must not introduce an rPrChange; got:\n{xml}"
    );
}

#[test]
fn deleted_math_ctrl_char_in_ctrlpr_roundtrips_verbatim() {
    let body = r#"<w:p><w:r><w:t>Eq: </w:t></w:r><m:oMath xmlns:m="http://schemas.openxmlformats.org/officeDocument/2006/math"><m:f><m:fPr><m:ctrlPr><w:del w:id="7" w:author="Joe Smith" w:date="2006-03-31T12:50:00Z"><w:rPr><w:rFonts w:ascii="Cambria Math" w:hAnsi="Cambria Math"/></w:rPr></w:del></m:ctrlPr></m:fPr><m:num><m:r><m:t>a</m:t></m:r></m:num><m:den><m:r><m:t>b</m:t></m:r></m:den></m:f></m:oMath></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);
    let xml = reserialize(&b);

    assert!(
        xml.contains("<m:ctrlPr>"),
        "ECMA-376 §22.1.2.23 / §17.13.5.13 — the control-property wrapper carrying the deletion must be preserved (opaque math round-tripped verbatim); got:\n{xml}"
    );
    // xmlRegex `<w:del[^>]*w:author="Joe Smith"[^>]*>` -> contains the author on
    // the deletion. Opaque-math verbatim preservation must keep the w:del and
    // its annotation attributes.
    assert!(
        xml.contains("<w:del") && xml.contains(r#"w:author="Joe Smith""#),
        "ECMA-376 §17.13.5.13 — the deleted math control character is represented by a w:del with author/date inside m:ctrlPr; verbatim preservation must keep the w:del and its annotation attributes; got:\n{xml}"
    );
    assert_opens_clean(
        &b,
        "ECMA-376 §17.13.5.13 / MS-OI29500 §2.1.329 — w:del inside m:ctrlPr with a w:rPr child is valid math-context markup Word opens cleanly",
    );
}

