#[test]
fn inserted_math_ctrl_char_no_rpr_opens_clean() {
    let body = r#"<w:p><m:oMath xmlns:m="http://schemas.openxmlformats.org/officeDocument/2006/math"><m:f><m:fPr><m:ctrlPr><w:ins w:id="5" w:author="Joe Smith" w:date="2006-03-31T12:50:00Z"/></m:ctrlPr></m:fPr><m:num><m:r><m:t>a</m:t></m:r></m:num><m:den><m:r><m:t>b</m:t></m:r></m:den></m:f></m:oMath></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);

    assert_opens_clean(
        &b,
        "MS-OI29500 §2.1.332 — Word does not require an rPr child of the inserted-math-control w:ins; an rPr-less w:ins inside m:ctrlPr is valid",
    );
    let xml = reserialize(&b);
    // xmlRegex `<w:ins[^>]*w:id="5"[^>]*/?>` -> verbatim: the w:ins carrying id 5.
    assert!(
        xml.contains(r#"<w:ins w:id="5""#),
        "ECMA-376 §17.13.5.16 — the inserted math control char is the w:ins inside m:ctrlPr; verbatim opaque-math preservation must keep the w:ins with its id; got:\n{xml}"
    );
}

