#[test]
fn math_ctrl_del_preserved_verbatim_in_ctrlpr() {
    let body = r#"<w:p><w:r><m:oMath xmlns:m="http://schemas.openxmlformats.org/officeDocument/2006/math"><m:nary><m:naryPr><m:chr m:val="∑"/><m:ctrlPr><w:del w:id="7" w:author="Mathematician" w:date="2026-02-02T00:00:00Z"/></m:ctrlPr></m:naryPr><m:sub><m:r><m:t>i</m:t></m:r></m:sub><m:sup><m:r><m:t>n</m:t></m:r></m:sup><m:e><m:r><m:t>x</m:t></m:r></m:e></m:nary></m:oMath></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);
    let xml = reserialize(&b);

    // xmlRegex `<m:ctrlPr>\s*<w:del[^>]*w:author="Mathematician"[^>]*/?>` ->
    // verbatim adjacency + author contains check.
    assert!(
        xml.contains("<m:ctrlPr><w:del") && xml.contains(r#"w:author="Mathematician""#),
        "EG_RPrMath / §22.1.2.23 — the math control deletion belongs as a direct child of m:ctrlPr; stemma's opaque passthrough must re-emit w:del there (with its author), not hoist it to run level; got:\n{xml}"
    );
    assert_opens_clean(
        &b,
        "EG_RPrMath / §17.13.5.13 — a w:del directly under m:ctrlPr is the schema-valid math-control deletion form; must open clean",
    );
}

